    for row in csv.DictReader(f):
        employees[int(row['employee_id'])] = row

# ---- COMPREHENSIVE BOTTLENECK SCORING ----
# Combine all signals with weights

# Signal 1: Code review time (slow reviewers)
review_times = defaultdict(list)
review_changes = defaultdict(int)
with open('code_review_001.csv') as f:
    for row in csv.DictReader(f):
        reviewer_id = int(row['reviewer_id'])
        req = parse_dt(row['requested_at'])
        comp = parse_dt(row['completed_at'])
        if req and comp:
            dur = (comp - req).total_seconds() / 3600
            review_times[reviewer_id].append(dur)
            if row['review_outcome'] == 'changes_requested':
                review_changes[reviewer_id] += 1

# Signal 2: Approval times
approval_times = defaultdict(list)
with open('approval_001.csv') as f:
    for row in csv.DictReader(f):
        approver_id = int(row['approver_id'])
        req = parse_dt(row['requested_at'])
        res = parse_dt(row['resolved_at'])
        if req and res:
            dur = (res - req).total_seconds() / 3600
            approval_times[approver_id].append(dur)

# Signal 3: Task event wait times
task_events = defaultdict(list)
for i in range(1,5):
    fname = f'task_event_00{i}.csv'
    try:
        with open(fname) as f:
            for row in csv.DictReader(f):
