                    'employee_id': int(row['employee_id']),
                    'event_type': row['event_type'],
                    'timestamp': parse_dt(row['timestamp'])
                })
    except FileNotFoundError:
        break
for task_id in task_events:
    task_events[task_id].sort(key=lambda x: x['timestamp'] or datetime.min)

wait_times_by_emp = defaultdict(list)
for task_id, events in task_events.items():
    for i in range(len(events)-1):
        curr = events[i]
        nxt = events[i+1]
        if curr['timestamp'] and nxt['timestamp']:
            wait = (nxt['timestamp'] - curr['timestamp']).total_seconds() / 3600
            wait_times_by_emp[nxt['employee_id']].append(wait)

