        resolved = parse_dt(row['resolved_at'])
        dep_dur = (resolved - created).total_seconds() / 3600 if created and resolved else 0
        for emp_id in task_assignments.get(blocking, set()):
            block_time_by_emp[emp_id] += dep_dur
            block_count_by_emp[emp_id] += 1

# Signal 5: Pager overload
pager_count = defaultdict(int)
for i in range(1,7):
    fname = f'message_metadata_00{i}.csv'
